{
  "title": "बेसिक मूव सेमांटिक्स",
  "group": "स्वामित्व",
  "options": [
    {
      "text": "नमस्ते, !",
      "hint": "सोचें कि 'philosopher' को मूव करने के बाद क्या होता है"
    },
    {
      "text": "नमस्ते, ज़ेनो ऑफ़ सिटियम!",
      "hint": "एक बार मान मूव हो जाने पर, क्या हम अभी भी इसका उपयोग कर सकते हैं?"
    },
    {
      "text": "नमस्ते, ज़ेनो ऑफ़ एलेआ!",
      "hint": "स्ट्रिंग में 'Citium' है, 'Elea' नहीं"
    },
    {
      "text": "नमस्ते, मार्कस ऑरेलियस",
      "hint": "जाँचें कि यह स्ट्रिंग सामग्री से मेल खाता है या नहीं"
    },
    {
      "text": "कम्पाइलेशन एरर: मूव के बाद वैल्यू उधार ली गई"
    },
    {
      "text": "रनटाइम एरर: नल पॉइंटर एक्सेप्शन",
      "hint": "Rust इन समस्याओं को कम्पाइल टाइम पर पकड़ लेता है"
    }
  ],
  "questionProse": [
    "जब आप इस कोड को चलाते हैं तो क्या होता है? आउटपुट या एरर का अनुमान लगाएँ:"
  ],
  "explanationProse": [
    "यह कोड Rust के स्वामित्व नियमों के कारण कम्पाइल नहीं होता। जब हम `philosopher` को `greeting` को असाइन करते हैं, तो String की स्वामित्व `greeting` को मूव हो जाता है। इस मूव के बाद, `philosopher` अब वैध नहीं रहता।\n\n      यहाँ इसे ठीक करने के तीन तरीके हैं:\n\n      1. स्ट्रिंग को क्लोन करें (एक नई कॉपी बनाता है):",
    "2. रेफ़रेंस का उपयोग करें (वैल्यू उधार लेता है):",
    "3. स्ट्रिंग स्लाइस का उपयोग करें (स्ट्रिंग का हिस्सा उधार लेता है):",
    "प्रत्येक समाधान के अलग उपयोग केस और प्रदर्शन प्रभाव होते हैं। क्लोनिंग महंगा है लेकिन स्वामित्व देता है, जबकि रेफ़रेंसेज़ सस्ते हैं लेकिन लाइफ़टाइम प्रतिबंध होते हैं।"
  ]
}
